#include <stdio.h>
#include <stdlib.h>

// Definition for a binary tree node.
typedef struct TreeNode {
    int data;
    struct TreeNode *left;
    struct TreeNode *right;
} TreeNode;

// Helper function to perform an in-order traversal of the BST
void inorderTraversal(TreeNode* node, int** values, int* index) {
    if (node) {
        inorderTraversal(node->left, values, index);
        (*values)[(*index)++] = node->data;
        inorderTraversal(node->right, values, index);
    }
}

// Function to find the kth smallest and kth largest values
int* kLargesSmall(TreeNode* root, int k, int* returnSize) {
    // Calculate the number of nodes in the tree
    int count = 0;
    TreeNode* temp = root;
    while (temp) {
        count++;
        temp = temp->left;
    }
    temp = root;
    while (temp->right) {
        count++;
        temp = temp->right;
    }

    // Allocate memory for the values array
    int* values = (int*)malloc(count * sizeof(int));
    int index = 0;

    // Perform in-order traversal and collect values
    inorderTraversal(root, &values, &index);

    // Find the kth smallest and kth largest values
    int kth_smallest = values[k - 1];
    int kth_largest = values[count - k];

    // Allocate memory for the result array
    int* result = (int*)malloc(2 * sizeof(int));
    result[0] = kth_smallest;
    result[1] = kth_largest;

    *returnSize = 2;
    return result;
}

